SELECT tournament_name
FROM tournaments
WHERE tournament_id = '1';

SELECT team_name 
FROM teams 
WHERE team_id = (SELECT champion_team_id FROM tournaments WHERE year = 1930);

SELECT team_name
FROM teams
WHERE team_id = (
    SELECT team_id
    FROM standings
    WHERE goals_for = (
        SELECT MAX(goals_for)
        FROM standings
    )
);
